const titlesRaw = '{{PERSON_TITLES}}';
const locationsRaw = '{{PERSON_LOCATIONS}}';
const keywordsRaw = '{{KEYWORDS}}';
const rangesRaw = '{{EMPLOYEE_RANGES}}';
const toArr = (s) => s.split('|').map(v => v.trim()).filter(Boolean);
const body = { per_page: 25, page: 1 };
const titles = toArr(titlesRaw);
if (titles.length) body.person_titles = titles;
const locations = toArr(locationsRaw);
if (locations.length) body.person_locations = locations;
const keywords = toArr(keywordsRaw);
if (keywords.length) body.q_keywords = keywords.join(' ');
const ranges = toArr(rangesRaw);
if (ranges.length) body.organization_num_employees_ranges = ranges;
return [{ json: body }];

const data = $input.first().json;
const people = data.people || [];
const results = people.slice(0, 25).map(p => ({
  apolloId: p.id,
  firstName: p.first_name || '',
  lastName: p.last_name || '',
  name: p.name || '',
  title: p.title || '',
  city: p.city || '',
  state: p.state || '',
  country: p.country || '',
  companyName: p.organization?.name || '',
  companyWebsite: p.organization?.website_url || '',
  industry: p.organization?.industry || '',
  employeeCount: p.organization?.estimated_num_employees || 0
}));
return results.map(r => ({ json: r }));

const apiKey = '{{APOLLO_API_KEY}}';
const results = [];
for (const item of $input.all()) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.apollo.io/api/v1/people/match',
      headers: { 'X-Api-Key': apiKey, 'Content-Type': 'application/json' },
      body: { id: item.json.apolloId, reveal_personal_emails: true },
      json: true
    });
    const p = res.person;
    if (!p) continue;
    const email = p.email || (p.personal_emails && p.personal_emails[0]) || '';
    if (!email) continue;
    results.push({ json: {
      apolloId: p.id,
      firstName: p.first_name || '',
      lastName: p.last_name || '',
      name: p.name || '',
      title: p.title || '',
      email: email,
      phone: (p.phone_numbers && p.phone_numbers[0]?.sanitized_number) || '',
      companyName: p.organization?.name || '',
      industry: p.organization?.industry || '',
      employeeCount: p.organization?.estimated_num_employees || 0
    } });
  } catch (e) { /* skip failed enrichments */ }
  await new Promise(r => setTimeout(r, 500));
}
return results;

const apiBase = '{{API_BASE_URL}}';
const clientId = '{{CLIENT_ID}}';
const apiSecret = '{{N8N_API_SECRET}}';
const n8nBase = '{{N8N_BASE_URL}}';
const template = '{{AGENT_PROMPT}}';
const headers = { 'x-api-secret': apiSecret, 'Content-Type': 'application/json' };
const results = [];

for (const item of $input.all()) {
  const c = item.json;
  try {
    // 1. Save to CRM
    const saveRes = await this.helpers.httpRequest({
      method: 'POST',
      url: apiBase + '/n8n/' + clientId + '/contacts',
      headers,
      body: { name: c.name, email: c.email, phone: c.phone, source: 'apollo', tags: ['apollo-prospect', c.industry || 'unknown'], summary: (c.title || '') + ' at ' + (c.companyName || '') },
      json: true
    });
    const contactId = saveRes.id || '';

    // 2. Build personalised message
    const message = template
      .replace(/\{\{firstName\}\}/g, c.firstName || '')
      .replace(/\{\{title\}\}/g, c.title || '')
      .replace(/\{\{companyName\}\}/g, c.companyName || '');

    // 3. Send outreach email
    if (c.email) {
      await this.helpers.httpRequest({
        method: 'POST',
        url: apiBase + '/n8n/' + clientId + '/messages/email',
        headers,
        body: { contactId, to: c.email, subject: 'Quick question, ' + (c.firstName || c.name || ''), body: message },
        json: true
      }).catch(() => {});
    }

    // 4. Forward to lead scoring
    await this.helpers.httpRequest({
      method: 'POST',
      url: n8nBase + '/webhook/lead-gen-' + clientId,
      headers: { 'Content-Type': 'application/json' },
      body: { contactId, name: c.name, email: c.email, phone: c.phone, source: 'apollo', title: c.title, companyName: c.companyName, industry: c.industry },
      json: true
    }).catch(() => {});

    results.push({ json: { contactId, name: c.name, email: c.email, status: 'processed' } });
  } catch (e) {
    results.push({ json: { name: c.name, email: c.email, status: 'failed', error: String(e).substring(0, 200) } });
  }
  // Rate limit: 1 second between contacts
  await new Promise(r => setTimeout(r, 1000));
}
return results;
